var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"제발…….","JPN":"頼む……","ENG":"Please...","TWN":"拜託……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"제발… 늦어서는 안 돼…!","JPN":"頼むから……間に合ってくれ……！","ENG":"Please... I can't be late...!","TWN":"拜託……千萬要趕上……！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L12_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그레이스 경, 어디 계십니까!","JPN":"グレース卿、どこですか！","ENG":"Dame Grace, where are you?!","TWN":"葛瑞絲小姐，你在哪裡！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L13_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그레이스 경!!","JPN":"グレース卿！！","ENG":"Dame Grace!!","TWN":"葛瑞絲小姐！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"본녀는 여기 있으니, 그리 서두르실 필요 없습니다.","JPN":"私はここにいます。そう焦る必要はありません。","ENG":"I am here. There's no need to be in such a rush.","TWN":"我就在這裡，不必那麼著急。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"아…!","JPN":"あ……！","ENG":"Ah...!","TWN":"啊…！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"숨을 돌리시지요. 그리 급해서야 나아갈 발을 헛디딜 뿐입니다.","JPN":"落ち着いてください。そんなに急いでいては、つまずきますよ。","ENG":"Take a moment to breathe. If you hurry, your steps will falter.","TWN":"稍微喘口氣吧。太過急躁只會讓你步伐不穩。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"여기서 이러고 계실 때가 아닙니다. 서둘러 이곳을 빠져나가야 해요!","JPN":"こうしている場合ではありません。早くここから出ないと！","ENG":"This isn't the time for calm! You need to leave, now!","TWN":"現在不是待在這裡的時候。我們必須趕快離開這裡！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"마왕 네헤모트가 이곳을 습격했습니다!","JPN":"魔王ネヘモトがここを襲撃しました！","ENG":"The Demon Lord Nehemoth is attacking this place!","TWN":"魔王貝赫莫特襲擊了這裡！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"아뇨. 그럴 필요는 없습니다.","JPN":"いいえ。その必要はございません。","ENG":"No. That won't be necessary.","TWN":"不，不需要那樣。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"경께서 다다르신 이곳은 이야기의 종착점이니까요.","JPN":"卿がたどり着いたここが、物語の終着点なのですから。","ENG":"You've arrived at the end of the story.","TWN":"因為你抵達的這個地方就是故事的終點。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……네?","JPN":"……はい？","ENG":"...What?","TWN":"……嗯？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그게… 갑자기 무슨 말씀이십니까?","JPN":"いきなり……何の話ですか？","ENG":"Wait... What are you talking about all of a sudden?","TWN":"你突然說什麼呢？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"이미 눈치채시지 않았습니까? 과거 별의 인도자는 이곳에서 죽음을 맞이했습니다.","JPN":"すでにお気づきなのでは？　過去、星の導き手はここで命を落としました。","ENG":"Surely you've realized it by now. The previous Star Guide met their end here.","TWN":"你難道還沒有察覺嗎？過去在這裡，星之引導者迎來了死亡。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그러니 더 이상 도망칠 필요도, 나아갈 필요도 없지요.","JPN":"ですので、もう逃げる必要も、進む必要もありません。","ENG":"So there's no more need to flee, and no reason to press forward.","TWN":"所以現在既不需要逃避，也不需要前進了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"하, 하지만 그레이스 경께서는 기사단의 창립자가 아니십니까?","JPN":"で、ですがグレース卿は騎士団の創立者ではないですか。","ENG":"But Dame Grace, you're the founder of the Order, aren't you?","TWN":"下，但是葛瑞絲小姐不是騎士團的創始人嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"여기가 끝이라면, 그런 건…….","JPN":"ここが終わりなら、それは……","ENG":"If this is the end, then...","TWN":"如果這裡是終點，那就……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"간단한 이야기입니다. 제국에 이어져야 할 별이 마왕의 힘으로 뒤틀렸지요.","JPN":"簡単な話です。帝国に継がれるべきの星が、魔王の力により歪曲されました。","ENG":"It's a simple story. The star that should have guided the Empire was twisted by the Demon Lord's power.","TWN":"這是一個簡單的故事。應與帝國相連的星星被魔王的力量扭曲了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"기사단의 설립은 별의 인도자를 중심으로 열두 가문의 정의로운 맹세라 알려져 있으나…….","JPN":"騎士団の設立は星の導き手を中心とした、12家門の正義の誓いであると知られておりますが……","ENG":"The founding of the Order is said to have been a noble vow by the twelve houses, centered around the Star Guide...","TWN":"騎士團的成立是以星之引導者為中心的十二家族的正義誓言而聞名……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"현실은 미련이 남아 과거를 답습했을 뿐입니다.","JPN":"現実は未練がましく過去を繰り返していただけです。","ENG":"But in truth, it was just a repetition of the past, driven by lingering regrets.","TWN":"現實只是因為留戀而重複過去罷了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그런 허망한 이야기예요.","JPN":"そんな虚しい物語なのです。","ENG":"A hollow tale.","TWN":"那是個荒謬的故事。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"평소와는 다르십니다, 그레이스 경.","JPN":"いつもとは違うではありませんか、グレース卿。","ENG":"You're not yourself, Dame Grace.","TWN":"你和平時不太一樣，葛瑞絲小姐。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"갑자기 그런 말씀을 한들, 저는…….","JPN":"いきなりそんなことを言われても、私は……","ENG":"Even if you say all this now, I...","TWN":"突然這樣說的話，我……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"별의 인도자는 낙오자였고 패배자였습니다.","JPN":"星の導き手は落ちこぼれで、敗北者でした。","ENG":"The Star Guide was a failure, a loser.","TWN":"星之引導者曾經是落伍者和失敗者。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"제가 만든 무구는 멸망을 막는데 기여하지 못했고, 동료들은 마왕 앞에 스러졌지요.","JPN":"私が作った武具は滅亡を止めることの役には立てず、仲間たちは魔王の前に倒れました。","ENG":"The Armaments I forged couldn't stop the world's ruin. My comrades fell before the Demon Lord.","TWN":"我製造的武具未能阻止毀滅，夥伴們在魔王面前倒下了。"},"stage":{"bg":"QLIPHOTH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"세상에 버려진 이들이 무엇 하나 지키지 못한 채 피로 얼룩진 마왕의 좌를 이었으니.","JPN":"世界に捨てられた者たちが、何一つ守れないまま血まみれの魔王の座を受け継いだのですから。","ENG":"We who were cast aside by the world took the Demon Lord's bloodstained throne, having saved nothing.","TWN":"被世界遺棄的人們未能守護任何東西，繼承了血染的魔王之座。"},"stage":{"bg":"QLIPHOTH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"이 이상 이야기를 계속해 무엇하겠습니까?","JPN":"これ以上お話しても無駄でしょう。","ENG":"What point is there in telling this story any further?","TWN":"再繼續講這個故事有什麼意義呢？"},"stage":{"bg":"QLIPHOTH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……정녕 이것이, 당신이 제게 보여주시고자 했던 결말입니까?","JPN":"……本当にこれが、あなたが私に見せようとしていた結末ですか？","ENG":"...Is this really the ending you meant to show me?","TWN":"……這真的是你想讓我看到的結局嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L2_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"예. 경께서 되찾고자 한 기사단의 정의이자 말로입니다.","JPN":"はい。卿が取り戻そうとしていた騎士団の正義であり、末路です。","ENG":"Yes. This is the justice and fate of the Order you wished to reclaim.","TWN":"是的。這是你想要找回的騎士團的正義和誓言。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"저희가 걸었던 길을 답습하기만 해봤자, 그 끝은 정해져 있어요.","JPN":"私たちがかつて歩んだ道をなぞるだけでは、同じ結末を迎えてしまうでしょう。","ENG":"As long as we retrace the path we once walked, the ending will always be the same.","TWN":"只要沿襲我們走過的路，結局就是註定的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그레이스 경도 알렌 경과 비슷한 말씀을 하시는군요.","JPN":"グレース卿も、アレン卿と同じような話をしますね。","ENG":"You sound just like Sir Allen.","TWN":"艾倫卿也說過類似的話。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그 분께서는 마지막 순간, 마음에도 없는 소리를 하시며 저를 밀어내려 했죠.","JPN":"あの方は最後の瞬間、心にもないことを言って私を遠ざけようとしました。","ENG":"He said something he didn't mean at the very end, trying to push me away.","TWN":"那個人在最後時刻，說著違心的話，試圖推開我。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"……제 말에 거짓은 없습니다.","JPN":"……私の言葉に、偽りはありません。","ENG":"…There is no falsehood in my words.","TWN":"這不是謊言。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그렇다면 제게 희망을 불어넣어 주신 이유는 무엇입니까?","JPN":"なら、どうして私に希望を与えてくれたのですか？","ENG":"Then why did you give me hope?","TWN":"那麼，你賦予我希望的理由是什麼呢？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"알렌 경이 해 주신 말들을, 왜 재차 긍정해주신 거죠?!","JPN":"アレン卿のお話を、どうして肯定したのですか！？","ENG":"Why did you echo the words Sir Allen left behind?","TWN":"為什麼要再次肯定艾倫卿說的話呢？！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"……확실히, 이기적인 욕심을 앞세운다면 다른 선택지가 있을 지도 모르겠네요.","JPN":"……確かに、自分勝手に欲望のままに進んでいたら、他の選択肢があったのかもしれません。","ENG":"...Perhaps if I had been selfish, there could've been another choice.","TWN":"……確實，如果以自私的欲望為優先，可能會有其他選擇。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"하지만 세월이 지나 각오가 마모된 것인지. 혹은, 찰나의 순간이 영원을 휩쓸었는지.","JPN":"ですが、時の流れとともに覚悟が薄れたせいか。それとも、刹那の瞬間が永遠を荒らしてしまったのか。","ENG":"But maybe my resolve faded over time, or a fleeting moment washed over eternity.","TWN":"但是隨著時間的流逝，決心是否已經磨損。或者，瞬間是否已經席捲了永恆。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"제 무능함의 죄악을 이제와 다른 사람에게 떠넘기고 싶지 않습니다.","JPN":"私が無能であるゆえの罪悪を、今更他人に押しつけたくはありません。","ENG":"I simply don't wish to burden someone else with the sin of my incompetence.","TWN":"我不想在現在把我無能的罪過推給別人。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"저는 그런 부탁한 적 없습니다!","JPN":"私はそんなことを頼んだ覚えはありません！","ENG":"I never asked you to do that!","TWN":"我從沒有拜託過這種事！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"당신은 상냥한 사람이에요, 에스텔.","JPN":"貴方は優しい人です、エステル。","ENG":"You're kind, Esther.","TWN":"你是個溫柔的人，艾斯特。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그렇기에…… 당신의 상냥함에 기대 현실을 외면하고 싶진 않군요.","JPN":"だから……貴方の優しさに頼りきって、現実から目を背けたくないのです。","ENG":"And because you're kind… I don't want to lean on you and turn away from reality.","TWN":"因此，我不想依賴你的溫柔來逃避現實。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"분명 알렌도 같은 마음이었을 겁니다.","JPN":"きっとアレンも同じ気持ちだったのでしょう。","ENG":"I'm sure Allen felt the same.","TWN":"艾倫肯定也是同樣的心情。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그레이스 경…?","JPN":"グレース卿……？","ENG":"Dame Grace...?","TWN":"葛瑞絲小姐…？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"늘 그랬듯, 한순간의 악몽이 감정을 지배했을 뿐입니다.","JPN":"いつもそうであったように、一瞬の悪夢が感情を支配しただけです。","ENG":"As always, I let a passing nightmare dictate my feelings.","TWN":"就像往常一樣，只是一瞬間的惡夢支配了情感。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그러니 모든 것을 잊고, 이제 그만 깨어나시지요.","JPN":"すべてを忘れ、もうお目覚めになってください。","ENG":"So forget everything and wake up.","TWN":"所以忘掉一切，現在該醒來了吧。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"잠시만… 그레이스 경!!","JPN":"待ってください……グレース卿！！","ENG":"Wait... Dame Grace!!","TWN":"等一下……葛瑞絲小姐！！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L43_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L45_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"순식간에 풍경이 변했다.","JPN":"一瞬で風景が変わった。","ENG":"The scenery shifted in an instant.","TWN":"瞬間風景就變了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"대체… 무슨 일이 일어난 거지?","JPN":"いったい……何が起きている……？","ENG":"What... just happened?","TWN":"這到底……發生了什麼事？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_QM_NULL","text":{"KOREA":"인도자의 별빛이라면 내가 취했다.","JPN":"導き手の星の光なら俺が手に入れた。","ENG":"I've taken the Star Guide's starlight.","TWN":"如果是引導者的星光，那我已經獲得了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_QM_NULL","text":{"KOREA":"가장 불확실한 요소를 이리도 쉽게 차지하다니… 수고를 덜었군.","JPN":"もっとも不確かな要素をこんなにも簡単に手に入れるとは……手間が省けたな。","ENG":"Securing the most uncertain element this easily... It saved me trouble.","TWN":"居然這麼輕鬆就掌握了最不確定的因素……省了不少功夫。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"좋아. 아주 훌륭해.","JPN":"ああ、本当に素晴らしい。","ENG":"Excellent. Truly excellent.","TWN":"很好。真的非常棒。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"이걸로 무구 계승에 필요한 모든 조건은 갖춰졌군.","JPN":"これで武具継承に必要なすべての条件が揃った。","ENG":"Now all the conditions for Armament succession are in place.","TWN":"這樣一來，繼承武具所需的所有條件都具備了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……당신은 설마, 카란티시르 경?","JPN":"……あなたはまさか、カランティシル卿？","ENG":"...Aren't you... Sir Carantisir?","TWN":"……你該不會是卡蘭堤西爾吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"말도 안 돼. 내가 지금 꿈을 꾸고 있는 건가?","JPN":"そんな。私は今夢を見ているのか？","ENG":"No way. This has to be a dream.","TWN":"這不可能。我現在是在做夢嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"오랜만이군, 애송이. 네놈은 예나 지금이나 변하지 않은 그대로야.","JPN":"久しぶりだな、小娘。貴様は昔も今も変わらないな。","ENG":"It's been a while, kid. Still the same, I see.","TWN":"好久不見，小丫頭。你從以前到現在都沒有改變。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"그래. 역겨운 자취를 풍기는 그 순진무구한 눈도 말이지.","JPN":"そうだ。腹立たしいあいつの痕跡をうかがわせる純粋な目もな。","ENG":"Yes. Even those sickeningly pure eyes of yours haven't changed.","TWN":"是啊，那散發著噁心氣息的純真無邪的眼睛也是。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"큭!?","JPN":"くっ！？","ENG":"Kgh?!","TWN":"呃！？"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L9_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"호오. 반응했나?","JPN":"ほう？　反応したか。","ENG":"Oh? You reacted?","TWN":"噢，有反應了嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"제 오빠의 덕을 봤다지만 기사라고 불릴 정도의 실력은 갖춘 모양이군.","JPN":"自分の兄のおかげとは言え、騎士とよばれるだけの実力はあるようだ。","ENG":"I suppose through your brother's help, you've got enough skill to pass for a knight.","TWN":"雖然說是沾了我哥哥的光，但看來你確實有能被稱為騎士的實力啊。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"이건… 사지타리우스 페일? 사라졌던 별의 무구가 왜 당신 손에 쥐어져 있는 겁니까?","JPN":"これは……サジタリウス・ペイル？　消えたはずの星の武具がどうしてあなたの手にあるのですか？","ENG":"...The Sagittarius Pale?! Why do you have one of the lost Star Armaments?!","TWN":"這是……射手座的武具？消失的星之武具為什麼會在你手中？"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"레드시프트가 잃어버린 무구는 분명 전임 기사단장이 쫓았을 텐데, 어떻게……!","JPN":"レッドシフトが失った武具は前騎士団長が追っていたはずなのに、どうやって……！","ENG":"The previous captain was pursuing the Red Shift's lost Armament. So how...?!","TWN":"紅移失去的武具前任騎士團長肯定有追查過，怎麼會……！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"크으, 으윽…!","JPN":"くぅ、ううっ……！","ENG":"Kgh...! Ngh...!","TWN":"唔呃，呃呃……！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BUMP"},{"id":"L17_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"오랜만에 봤다고 감각이 무뎌졌군. 너 같은 쓰레기가 내게 질문하다니 말이야.","JPN":"久しぶりに会ったから感覚が鈍くなったか？　貴様のようなクズが俺に質問をするとは。","ENG":"It's been a while, so you got dull. For a trash like you to question me.","TWN":"喔，好久不見，感覺都遲鈍了。像你這樣的廢物居然敢向我提問。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"허나 다행스럽게도 난 지금 기분이 좋다.","JPN":"だが幸い、今の俺は気分がいい。","ENG":"Yet, thankfully I'm in a good mood right now.","TWN":"不過幸運的是，我現在心情很好。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"그러니, 적어도 네놈을 기사로서 예우해주도록 하지.","JPN":"だから、せめて貴様を騎士として礼遇してやるとしよう。","ENG":"So I'll do you the courtesy of treating you like a knight.","TWN":"所以，至少我會以騎士的禮儀來對待你。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"검을 들어라. <color=#ffd34c>슈발리에</color>의 기사여.","JPN":"剣を持て。<color=#ffd34c>シュヴァリエ</color>の騎士よ。","ENG":"Draw your sword, knight of <color=#ffd34c>Chevalier</color>.","TWN":"舉起劍吧，<color=#ffd34c>騎士</color>。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"그 천한 목숨을, 내 친히 거둬주마.","JPN":"その下賤な命を、この俺が摘み取ってやろう。","ENG":"I'll personally relieve you of that pathetic life.","TWN":"我會親手收割你的卑賤生命。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};